public boolean areEncodedStringsEqual(String s1, String s2) {
    StringBuilder decoded1 = new StringBuilder(), decoded2 = new StringBuilder();

    for(int i = 0; i < s1.length(); ++i) {
        if(Character.isDigit(s1.charAt(i))) {
            int count = s1.charAt(i) - '0';
            while(count-- > 0) decoded1.append(s1.charAt(i - 1));
        } else decoded1.append(s1.charAt(i));
    }

    for(int i = 0; i < s2.length(); ++i) {
        if(Character.isDigit(s2.charAt(i))) {
            int count = s2.charAt(i) - '0';
            while(count-- > 0) decoded2.append(s2.charAt(i - 1));
        } else decoded2.append(s2.charAt(i));
    }

    return decoded1.toString().equals(decoded2.toString());
}
```


